type SimpleCache struct {
    cache map[interface{}]interface{}
}

func NewSimpleCache() *SimpleCache {
    return &SimpleCache{cache: make(map[interface{}]interface{})}
}

func (c *SimpleCache) Put(key, value interface{}) {
    c.cache[key] = value
}

func (c *SimpleCache) Get(key interface{}) interface{} {
    return c.cache[key]
